   119	                    opensession_core::trace::EventType::ToolCall { .. } => tool_calls += 1,
   120	                    opensession_core::trace::EventType::ToolResult { .. } => tool_results += 1,
   121	                    opensession_core::trace::EventType::FileEdit { .. } => file_edits += 1,
   122	                    opensession_core::trace::EventType::FileRead { .. } => file_reads += 1,
   123	                    opensession_core::trace::EventType::ShellCommand { .. } => shell_cmds += 1,
   124	                    _ => other += 1,
   125	                }
   126	            }
   127	
   128	            println!("=== Event type breakdown ===");
   129	            println!("  UserMessage:  {}", user_msgs);
   130	            println!("  AgentMessage: {}", agent_msgs);
   131	            println!("  Thinking:     {}", thinking);
   132	            println!("  ToolCall:     {}", tool_calls);
   133	            println!("  ToolResult:   {}", tool_results);
   134	            println!("  FileEdit:     {}", file_edits);
   135	            println!("  FileRead:     {}", file_reads);
   136	            println!("  ShellCommand: {}", shell_cmds);
   137	            println!("  Other:        {}", other);
   138	            println!("  TOTAL:        {}", session.events.len());
   139	
   140	            assert!(user_msgs > 0, "should have at least one user message");
   141	            assert!(agent_msgs > 0, "should have at least one agent message");
   142	        }
   143	        Err(e) => {
   144	            panic!("FAILED to parse Cursor database: {:#}", e);
   145	        }
   146	    }
   147	}
