   149	/// Test that we can deserialize ALL conversations from the real DB.
   150	#[test]
   151	#[ignore = "requires real Cursor database"]
   152	fn deserialize_all_conversations_from_real_db() {
   153	    let path = Path::new(real_db_path());
   154	    if !path.exists() {
   155	        eprintln!("Skipping: Cursor database not found");
   156	        return;
   157	    }
   158	
   159	    let conn =
   160	        rusqlite::Connection::open_with_flags(path, rusqlite::OpenFlags::SQLITE_OPEN_READ_ONLY)
   161	            .expect("Failed to open database");
   162	
   163	    let mut stmt = conn
   164	        .prepare("SELECT key, value FROM cursorDiskKV WHERE key LIKE 'composerData:%'")
   165	        .expect("Failed to prepare statement");
   166	
   167	    let rows: Vec<(String, String)> = stmt
   168	        .query_map([], |row| {
   169	            let key: String = row.get(0)?;
   170	            let value_ref = row.get_ref(1)?;
   171	            let value = match value_ref {
   172	                rusqlite::types::ValueRef::Text(bytes) => {
   173	                    String::from_utf8_lossy(bytes).into_owned()
   174	                }
   175	                rusqlite::types::ValueRef::Blob(bytes) => {
   176	                    String::from_utf8_lossy(bytes).into_owned()
   177	                }
   178	                _ => String::new(),
   179	            };
   180	            Ok((key, value))
   181	        })
   182	        .expect("query_map failed")
   183	        .filter_map(|r| r.ok())
   184	        .collect();
   185	
   186	    println!("Total composerData entries: {}", rows.len());
   187	
   188	    let mut valid_json = 0;
   189	    let mut empty_value = 0;
   190	    let mut has_conversations = 0;
   191	    let mut json_parse_fail = 0;
   192	
   193	    for (key, value) in &rows {
   194	        if value.is_empty() {
   195	            empty_value += 1;
   196	            continue;
   197	        }
   198	
   199	        match serde_json::from_str::<serde_json::Value>(value) {
   200	            Ok(val) => {
   201	                valid_json += 1;
   202	                let conv_len = val
   203	                    .get("conversation")
   204	                    .and_then(|v| v.as_array())
   205	                    .map(|a| a.len())
   206	                    .unwrap_or(0);
   207	                if conv_len > 0 {
   208	                    has_conversations += 1;
   209	                }
   210	            }
   211	            Err(e) => {
   212	                json_parse_fail += 1;
   213	                if json_parse_fail <= 3 {
   214	                    println!(
   215	                        "  JSON parse fail: {} -> {} (value len={})",
   216	                        key,
   217	                        e,
   218	                        value.len()
   219	                    );
   220	                }
   221	            }
   222	        }
   223	    }
   224	
   225	    println!("\n=== Database content summary ===");
   226	    println!("  Total entries:              {}", rows.len());
   227	    println!("  Empty values:               {}", empty_value);
   228	    println!("  Valid JSON:                 {}", valid_json);
   229	    println!("  With conversations (>0):    {}", has_conversations);
   230	    println!("  JSON parse failures:        {}", json_parse_fail);
   231	
   232	    // The parser should be able to handle all valid JSON entries
   233	    assert!(
   234	        valid_json > 0,
   235	        "Should have at least some valid JSON entries"
   236	    );
   237	    assert!(
   238	        has_conversations > 0,
   239	        "Should have at least some conversations"
   240	    );
   241	
   242	    // All non-empty values should be valid JSON
   243	    let non_empty = rows.len() - empty_value;
   244	    if non_empty > 0 {
   245	        let json_success_rate = valid_json as f64 / non_empty as f64;
   246	        println!(
   247	            "  JSON success rate:          {:.1}%",
   248	            json_success_rate * 100.0
   249	        );
   250	        assert!(
   251	            json_success_rate > 0.95,
   252	            "JSON parse rate should be > 95% for non-empty values"
   253	        );
   254	    }
   255	}
